        String normalizedScheme = scheme.toLowerCase(Locale.ROOT);
        if (!"http".equals(normalizedScheme) && !"https".equals(normalizedScheme)) {
            throw new IOException("Only HTTP and HTTPS URLs are allowed");
        }

        if (uri.getUserInfo() != null) {
